const materializedSamples = new Map();

function materializeSample(sampleCount, sample) {
  const cached = materializedSamples.get(sampleCount);
  if (cached) return cached;
  const points = [];
  const packed = sample.packed;
  for (let i = 0; i < packed.length; i += 8) {
    points.push({
      x: packed[i],
      y: packed[i + 1],
      distance: packed[i + 2],
      u: packed[i + 3],
      tangent: { x: packed[i + 4], y: packed[i + 5] },
      normal: { x: packed[i + 6], y: packed[i + 7] }
    });
  }
  const sampledPath = { totalLength: sample.totalLength, points };
  materializedSamples.set(sampleCount, sampledPath);
  return sampledPath;
}

export function getPrecomputedSnakePath(pathD, sampleCount) {
  if (pathD !== ROUTE_C_STRINGS_PATH_D) return null;
  const sample = ROUTE_C_STRING_SAMPLES[String(sampleCount)];
  return sample ? materializeSample(sampleCount, sample) : null;
}
